<script setup>
import { computed, reactive, ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import { getExamCalendar, getExams, getFreeClassrooms, getGpa, getSchedule, getScoreStatistics, getScores, getTeacherCourses, getTodayCourses } from '@/api/campus'

const tab = ref('course')
const data = ref(null)
const extras = ref(null)
const selectedDay = ref(new Date().getDay() || 7)
const form = reactive({ semester: '2026-2027-1', week: 1, building: '', date: '', timeSlot: '', teacherId: '', type: '', month: '2026-07' })
const tabs = [['course','课程'],['score','成绩'],['exam','考试'],['room','空教室']]
const days = [{ id: 1, name: '周一' }, { id: 2, name: '周二' }, { id: 3, name: '周三' }, { id: 4, name: '周四' }, { id: 5, name: '周五' }, { id: 6, name: '周六' }, { id: 7, name: '周日' }]
const dayName = (id) => days.find((day) => day.id === Number(id))?.name || `周${id}`
const listOf = (value, key) => Array.isArray(value) ? value : (Array.isArray(value?.[key]) ? value[key] : [])
const scheduleRows = computed(() => listOf(data.value, 'schedule'))
const courseTimeline = computed(() => scheduleRows.value.filter((item) => Number(item.dayOfWeek) === Number(selectedDay.value)).sort((a, b) => String(a.timeSlot || '').localeCompare(String(b.timeSlot || ''))))
const scoreRows = computed(() => listOf(data.value, 'scores'))
const examRows = computed(() => Array.isArray(data.value) ? data.value : [])
const roomRows = computed(() => Array.isArray(data.value) ? data.value : [])
const scoreAverage = computed(() => data.value?.average ?? '-')
const scoreCount = computed(() => data.value?.count ?? scoreRows.value.length)
const scorePercent = (score) => `${Math.min(100, Math.max(0, Number(score) || 0))}%`
const examDays = (date) => { const daysLeft = Math.ceil((new Date(`${date}T00:00:00`).getTime() - new Date(new Date().toDateString()).getTime()) / 86400000); return daysLeft >= 0 ? (daysLeft === 0 ? '今天' : `${daysLeft} 天后`) : '已结束' }

async function load() {
  if ((tab.value === 'course' || tab.value === 'score' || tab.value === 'exam') && !uni.getStorageSync('token')) return uni.navigateTo({ url: '/pages/auth/index' })
  extras.value = null
  if (tab.value === 'course') data.value = await getSchedule({ semester: form.semester, week: form.week })
  if (tab.value === 'score') data.value = await getScores({ semester: form.semester, type: form.type })
  if (tab.value === 'exam') data.value = await getExams()
  if (tab.value === 'room') data.value = await getFreeClassrooms({ building: form.building, date: form.date, timeSlot: form.timeSlot })
}
async function secondary(action) { if (action === 'today') extras.value = await getTodayCourses(); if (action === 'teacher') extras.value = await getTeacherCourses(form.teacherId); if (action === 'gpa') extras.value = await getGpa(); if (action === 'stats') extras.value = await getScoreStatistics(); if (action === 'calendar') extras.value = await getExamCalendar(form.month) }
function select(value) { tab.value = value; load() }
function chooseDay(day) { selectedDay.value = day; if (!scheduleRows.value.length) load() }
function changeWeek(offset) { form.week = Math.max(1, Number(form.week) + offset); load() }
onLoad((options) => { if (options.tab) tab.value = options.tab; load() })
</script>

<template>
  <view class="screen academic-page">
    <view class="tabs"><view v-for="item in tabs" :key="item[0]" class="tab" :class="{active:tab===item[0]}" @click="select(item[0])">{{ item[1] }}</view></view>

    <view v-if="tab==='course'" class="course-view">
      <view class="course-header"><view><text class="eyebrow">MY SCHEDULE</text><text class="page-title">我的课表</text><text class="page-sub">第 {{ form.week }} 周 · {{ form.semester }}</text></view><view class="week-switch"><button @click="changeWeek(-1)">‹</button><text>第 {{ form.week }} 周</text><button @click="changeWeek(1)">›</button></view></view>
      <view class="semester-bar"><input v-model="form.semester" class="semester-input" placeholder="学期，如 2026-2027-1" confirm-type="search" @confirm="load"/><button @click="load">查询课表</button></view>
      <scroll-view scroll-x class="day-scroll" :show-scrollbar="false"><view class="day-row"><view v-for="day in days" :key="day.id" class="day-chip" :class="{active:selectedDay===day.id}" @click="chooseDay(day.id)"><text>{{ day.name }}</text><text class="day-dot" v-if="day.id === (new Date().getDay() || 7)">今天</text></view></view></scroll-view>
      <view class="timeline"><view v-for="(slot,index) in courseTimeline" :key="slot.timeSlot || index" class="timeline-row"><view class="time-axis"><text class="time-label">{{ slot.timeSlot || '待定' }}</text><view class="axis-line" :class="{last:index===courseTimeline.length-1}" /></view><view class="course-stack"><view v-for="(course,courseIndex) in (slot.courses || [slot])" :key="course.id || courseIndex" class="course-card" :style="{ '--course-color': course.color || '#7c5cd6' }"><view class="course-name">{{ course.name || course.courseName }}</view><view class="course-location">{{ course.building || '教学楼' }} {{ course.classroom || '待定' }}</view><view class="course-bottom"><text>{{ course.teacher || '教师待定' }}</text><text>{{ course.weeks || '全学期' }}</text></view></view></view></view><view v-if="!courseTimeline.length" class="empty-card"><text class="empty-icon">✓</text><text>这一天没有课程</text><text class="muted">可以查看其他日期或切换周次</text></view></view>
      <view class="panel compact-tools"><view class="tool-title">课表工具</view><button class="secondary-btn today-btn" @click="secondary('today')">查看今日全部课程</button><view class="teacher-query"><input v-model="form.teacherId" class="field inline" type="number" placeholder="输入教师 ID"/><button class="secondary-btn" @click="secondary('teacher')">查询教师课程</button></view></view>
    </view>

    <view v-else class="secondary-view">
      <view class="view-heading"><view><text class="eyebrow">ACADEMIC CENTER</text><text class="page-title">{{ tabs.find(item => item[0] === tab)[1] }}</text></view><button class="week-btn" @click="load">刷新</button></view>
      <view class="panel query"><template v-if="tab==='score'"><input v-model="form.semester" class="field" placeholder="学期，如 2026-2027-1"/><picker :range="['全部','考试','平时']" @change="form.type=['','EXAM','USUAL'][$event.detail.value]"><view class="field picker">成绩类型：{{ {'':'全部',EXAM:'考试',USUAL:'平时'}[form.type] }}<text>⌄</text></view></picker></template><template v-if="tab==='room'"><input v-model="form.building" class="field" placeholder="教学楼（可选）"/><input v-model="form.date" class="field" placeholder="日期 YYYY-MM-DD"/><input v-model="form.timeSlot" class="field" placeholder="节次，如 1-2节"/></template><template v-if="tab==='exam'"><input v-model="form.month" class="field" placeholder="筛选月份 YYYY-MM"/></template><button class="primary-btn" @click="load">查询</button></view>
      <view v-if="tab==='score'" class="score-summary"><view><text class="summary-label">GPA</text><text class="summary-value">{{ data?.gpa ?? '-' }}</text></view><view><text class="summary-label">平均分</text><text class="summary-value">{{ scoreAverage }}</text></view><view><text class="summary-label">已修课程</text><text class="summary-value">{{ scoreCount }}</text></view></view><view v-if="tab==='score'" class="action-row"><button class="secondary-btn" @click="secondary('gpa')">GPA 详情</button><button class="secondary-btn" @click="secondary('stats')">成绩分析</button></view>
      <view v-if="tab==='exam'" class="action-row"><button class="secondary-btn" @click="secondary('calendar')">查看月历</button></view>
      <view v-if="tab==='score'" class="score-list"><view v-for="(item,index) in scoreRows" :key="item.id || index" class="score-card"><view class="score-top"><view><text class="score-name">{{ item.courseName || item.name }}</text><text class="score-code">{{ item.courseCode || item.semester || '课程成绩' }}</text></view><text class="score-number">{{ item.score ?? '-' }}</text></view><view class="score-progress"><view :style="{width:scorePercent(item.score)}" /></view><view class="score-meta"><text>{{ item.grade || '未评级' }}</text><text>{{ item.credit || 0 }} 学分</text><text>{{ item.type || '成绩' }}</text></view></view></view>
      <view v-if="tab==='exam'" class="exam-list"><view v-for="(item,index) in examRows" :key="item.id || index" class="exam-card"><view class="exam-date"><text>{{ item.examDate?.slice(5) || '--' }}</text><text>{{ examDays(item.examDate) }}</text></view><view class="exam-main"><text class="exam-name">{{ item.courseName || item.name }}</text><text>{{ item.examTime || '时间待定' }}</text><text>{{ item.building || '考场待定' }} {{ item.classroom || '' }} · {{ item.seatNumber ? `座位 ${item.seatNumber}` : '座位待定' }}</text></view><view class="exam-status">{{ item.status || '待考试' }}</view></view></view>
      <view v-if="tab==='room'" class="room-list"><view v-for="(item,index) in roomRows" :key="item.id || index" class="room-card"><view class="room-icon">⌂</view><view class="room-main"><text class="room-name">{{ item.building || '教学楼' }} · {{ item.name || item.classroom }}</text><text>{{ item.timeSlot || '全天可用' }} · 容量 {{ item.capacity || '--' }} 人</text></view><text class="room-state">空闲</text></view></view>
      <view v-if="extras" class="panel result"><view class="section-title">补充结果</view><view v-for="(item,index) in (Array.isArray(extras)?extras:[extras])" :key="index" class="result-row">{{ item.courseName || item.name || item.semester || item.gpa || item.average || item.examDate || '查询成功' }}<text class="muted"> {{ item.timeSlot || item.score || item.classroom || item.count || '' }}</text></view></view>
      <view v-if="((tab==='score'&&!scoreRows.length)||(tab==='exam'&&!examRows.length)||(tab==='room'&&!roomRows.length))" class="empty-state">暂无数据</view>
    </view>
  </view>
</template>

<style scoped lang="scss">
