osition:relative;flex:0 0 125rpx;padding-top:6rpx}.time-label{display:block;color:$campus-text-secondary;font-size:21rpx;line-height:1.35}.axis-line{position:absolute;top:42rpx;left:42rpx;width:2rpx;height:calc(100% - 20rpx);background:#ded4f2}.axis-line::before{position:absolute;top:-9rpx;left:-7rpx;width:14rpx;height:14rpx;border:3rpx solid #7c5cd6;border-radius:50%;background:#fff;content:''}.axis-line.last{height:0}.course-stack{flex:1;min-width:0}.course-card{position:relative;min-width:0;min-height:126rpx;margin-bottom:18rpx;padding:22rpx 22rpx 18rpx;border-left:7rpx solid var(--course-color);border-radius:18rpx;background:#fff;box-shadow:0 8rpx 26rpx rgba(124,92,214,.1)}.course-name{color:$campus-text-main;font-size:29rpx;font-weight:700}.course-location{margin-top:9rpx;color:$campus-text-secondary;font-size:22rpx}.course-bottom{display:flex;justify-content:space-between;margin-top:16rpx;color:$campus-text-muted;font-size:20rpx}.empty-card{display:flex;align-items:center;flex-direction:column;padding:70rpx 0;color:$campus-text-secondary;gap:8rpx}.empty-icon{display:flex;align-items:center;justify-content:center;width:70rpx;height:70rpx;border-radius:50%;background:#efe9fc;color:#7c5cd6;font-size:34rpx}.compact-tools{margin-top:8rpx;padding:24rpx}.tool-title{margin-bottom:16rpx;font-weight:700}.today-btn{width:100%;margin:0 0 14rpx}.teacher-query{display:grid;grid-template-columns:minmax(0,1fr) 220rpx;gap:14rpx}.teacher-query .secondary-btn{width:100%;margin:0}.inline{min-width:0;margin:0}.secondary-view{padding-top:12rpx}.query{margin-bottom:20rpx}.query .field{display:flex;align-items:center;justify-content:space-between}.query .primary-btn{margin-top:2rpx}.action-row{display:flex;gap:14rpx;margin-bottom:20rpx}.action-row .secondary-btn{flex:1}.score-summary{display:grid;grid-template-columns:repeat(3,1fr);margin-bottom:20rpx;padding:26rpx 10rpx;border-radius:22rpx;background:linear-gradient(135deg,#241457,#7c5cd6);color:#fff;box-shadow:0 12rpx 30rpx rgba(36,20,87,.2)}.score-summary view{display:flex;align-items:center;flex-direction:column;border-right:1rpx solid rgba(255,255,255,.2)}.score-summary view:last-child{border:0}.summary-label{color:rgba(255,255,255,.72);font-size:20rpx}.summary-value{margin-top:8rpx;font-size:38rpx;font-weight:800}.score-card{margin-bottom:16rpx;padding:24rpx;border:1rpx solid #ece4fb;border-radius:22rpx;background:#fff;box-shadow:0 8rpx 26rpx rgba(124,92,214,.07)}.score-top{display:flex;align-items:flex-start;justify-content:space-between}.score-name,.score-code{display:block}.score-name{font-size:29rpx;font-weight:700}.score-code{margin-top:6rpx;color:$campus-text-muted;font-size:20rpx}.score-number{color:#694ab9;font-size:42rpx;font-weight:800}.score-progress{height:10rpx;margin:20rpx 0 14rpx;border-radius:5rpx;background:#eee9f7}.score-progress view{height:100%;border-radius:5rpx;background:linear-gradient(90deg,#7c5cd6,#b06fd0)}.score-meta{display:flex;gap:24rpx;color:$campus-text-muted;font-size:21rpx}.exam-card,.room-card{display:flex;align-items:center;margin-bottom:16rpx;padding:22rpx;border:1rpx solid #ece4fb;border-radius:22rpx;background:#fff;box-shadow:0 8rpx 26rpx rgba(124,92,214,.07)}.exam-date{display:flex;align-items:center;flex-direction:column;justify-content:center;flex:0 0 112rpx;margin-right:18rpx;padding:13rpx 8rpx;border-radius:17rpx;background:#f0eafa;color:#694ab9}.exam-date text:first-child{font-size:32rpx;font-weight:800}.exam-date text:last-child{margin-top:5rpx;font-size:19rpx}.exam-main{display:flex;flex:1;min-width:0;flex-direction:column;gap:7rpx;color:$campus-text-secondary;font-size:21rpx}.exam-name{overflow:hidden;color:$campus-text-main;font-size:28rpx;font-weight:700;white-space:nowrap;text-overflow:ellipsis}.exam-status{align-self:flex-start;padding:8rpx 12rpx;border-radius:999rpx;background:#fff0df;color:#c87528;font-size:19rpx}.room-icon{display:flex;align-items:center;justify-content:center;width:62rpx;height:62rpx;margin-right:18rpx;border-radius:18rpx;background:#e8f1ff;color:#3976c9;font-size:30rpx}.room-main{display:flex;flex:1;min-width:0;flex-direction:column;gap:8rpx}.room-name{color:$campus-text-main;font-size:27rpx;font-weight:700}.room-main text:last-child{color:$campus-text-muted;font-size:21rpx}.room-state{padding:8rpx 12rpx;border-radius:999rpx;background:#e6f7f1;color:#288469;font-size:20rpx}.result-row{padding:14rpx 0;border-bottom:1rpx solid #ebeef5}
</style>
